function VF({ l, v, u }) {
  const has = v!=null && v!=='';
  return (
    <div>
      <div style={{ fontSize:10.5, color:'#64748b', fontWeight:600, letterSpacing:'0.04em', textTransform:'uppercase', marginBottom:3 }}>{l}</div>
      <div style={{ fontSize:14, fontWeight:600, color:has?'#1e293b':'#d1d5db', padding:'5px 0', borderBottom:`1.5px solid ${has?'#e2e8f0':'#f8fafc'}` }}>
        {has?<>{v}{u?<span style={{color:'#94a3b8',fontSize:11,marginLeft:4}}>{u}</span>:''}</>:'—'}
      </div>
    </div>
  );
}

function FraudBadge({ v }) {
  const M = { GENUINE:['#059669','#ecfdf5'], NEEDS_REVIEW:['#d97706','#fffbeb'], SUSPICIOUS:['#f97316','#fff7ed'], LIKELY_DUMMY:['#dc2626','#fef2f2'] };
  const [c,bg] = M[v]||['#64748b','#f8fafc'];
  return <span style={{ background:bg, color:c, padding:'4px 10px', borderRadius:8, fontSize:10.5, fontWeight:700, border:`1.5px solid ${c}25`, letterSpacing:'0.03em' }}>{v}</span>;
}

function Badge({ text, bg, color }) {
  return <span style={{ background:bg, color, padding:'4px 10px', borderRadius:8, fontSize:10.5, fontWeight:700 }}>{text}</span>;
}

function MiniBtn({ icon, color, onClick }) {
  return <button className="ipqc-btn" onClick={onClick} style={{ padding:'6px 12px', background:`${color}0d`, color, border:`1.5px solid ${color}25`, borderRadius:8, fontSize:13, cursor:'pointer', fontWeight:600 }}>{icon}</button>;
}

function Spinner() {
  return <span style={{ display:'inline-block', width:14, height:14, border:'2px solid rgba(255,255,255,0.3)', borderTopColor:'#fff', borderRadius:'50%', animation:'spin 0.6s linear infinite' }}/>;
}

const TD = { padding:'12px 16px', borderBottom:'1px solid #f1f5f9', fontSize:13.5 };

export default IPQCFormPage;
